  EVIDENCE_FOUND=""
  EVIDENCE_STALE=""
  if [ ! -f "$TRANSCRIPT_PATH" ]; then
    return
  fi
  local NOW_EPOCH
  NOW_EPOCH=$(date -u +%s)
  local WINDOW_SEC=$(( FRESHNESS_MIN * 60 ))

