\"$EVIDENCE_FOUND\" ]; then\n139\t    exit 0\n140\t  fi\n141\t\n142\t  # Build denial reason\n143\t  if [ -n \"$EVIDENCE_STALE\" ]; then\n144\t    REASON=\"Evidence is stale: $EVIDENCE_STALE. Re-read the evidence file within the $FRESHNESS_MIN-minute freshness window before claiming success.\"\n145\t  else\n146\t    REQUIRED_LIST=$(echo \"$REQUIRED_READS\" | tr '\\n' ', ' | sed 's/,$//')\n147\t    REASON=\"Cannot write to $FILE_PATH without first Reading evidence. Required: one of [$REQUIRED_LIST]. Read the relevant evidence file, then retry the write.\"\n148\t  fi\n149\t\n150\t  # Emit JSON deny decision\n151\t  jq -n --arg reason \"$REASON\" '{\n152\t    hookSpecificOutput: {\n153\t      hookEventName: \"PreToolUse\",\n154\t      permissionDecision: \"deny\",\n155\t      permissionDecisionReason: $reason\n156\t    }\n157\t  }'\n158\t  exit 2\n159\tfi\n160\t\n161\t# ---------------------------------------------------------------------------\n162\t# Over-reliance check (opt-in, default OFF)\n163\t# Gate: CATALYST_VERIFY_OVERRELIANCE=1\n164\t# Fires when no claim rule matched (general Write/Edit) but the content is\n165\t# large (>= CATALYST_OVERRELIANCE_MIN_BYTES) AND no file was Read in-window.\n166\t# Emits \"ask\" (not \"deny\") to surface a trust caution without hard-blocking.\n167\t# ---------------------------------------------------------------------------\n168\tOVERRELIANCE_ON=\"${CATALYST_VERIFY_OVERRELIANCE:-0}\"\n169\tif [ \"$OVERRELIANCE_ON\" = \"1\" ]; then\n170\t  MIN_BYTES=\"${CATALYST_OVERRELIANCE_MIN_BYTES:-4000}\"\n171\t\n172\t  # Measure the write payload size\n173\t  # Write: tool_input.content; Edit: tool_input.new_string\n174\t  WRITE_CONTENT=$(echo \"$INPUT\" | jq -r '.tool_input.content // .tool_input.new_string // \"\"')\n175\t  CONTENT_LEN=${#WRITE_CONTENT}\n176\t\n177\t  if [ \"$CONTENT_LEN\" -ge \"$MIN_BYTES\" ]; then\n178\t    # Check whether ANY file was Read in the freshness window (not just claim files)\n179\t    ANY_RECENT_READ=\"\"\